  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num / nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if (pid == nproc - 1) k2 = points->num;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  float myhiz = 0;
  for (long kk = k1; kk < k2; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hizs[pid] = myhiz;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for (int i2 = 0; i2 < nproc; i2++) hiz += hizs[i2];

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = k1; kk < k2; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if (pid == 0) {
      free(hizs);
      *kfinal = k;
    }
    return cost;
  }

  if (pid == 0) shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) { hiz = z; z = (hiz + loz) / 2.0; i = 0; }
    if (pid == 0) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if (pid == 0) {
    numfeasible = selectfeasible_fast(points, &feasible, kmin, pid, barrier);
    for (int ii = 0; ii < points->num; ii++) {
      is_center[points->p[ii].assign] = true;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  while (1) {
    lastcost = cost;
    cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
               (long)(ITER * kmax * log((float)kmax)), 0.1f, pid, barrier);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
                 (long)(ITER * kmax * log((float)kmax)), 0.001f, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z; z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) break;

#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }

  if (pid == 0) {
    free(feasible);
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i, k;
  bool *is_a_median = (bool *)calloc((size_t)points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) is_a_median[points->p[i].assign] = 1;
  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, (size_t)points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }
  centers->num = k;
  free(is_a_median);
}

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg = (pkmedian_arg_t*)arg_;
  pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
  return NULL;
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  pthread_barrier_t barrier;
#ifdef ENABLE_THREADS
  pthread_barrier_init(&barrier, NULL, nproc);
#endif
  pthread_t* threads = new pthread_t[nproc];
  pkmedian_arg_t* arg = new pkmedian_arg_t[nproc];

  for (int i = 0; i < nproc; i++) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;
    arg[i].barrier = &barrier;
#ifdef ENABLE_THREADS
    pthread_create(threads + i, NULL, localSearchSub, (void*)&arg[i]);
#else
    localSearchSub(&arg[0]);
#endif
  }

  for (int i = 0; i < nproc; i++) {
#ifdef ENABLE_THREADS
    pthread_join(threads[i], NULL);
#endif
  }

  delete[] threads;
  delete[] arg;
#ifdef ENABLE_THREADS
  pthread_barrier_destroy(&barrier);
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc((size_t)chunksize * dim * sizeof(float));
  float* centerBlock = (float*)malloc((size_t)centersize * dim * sizeof(float));
  long* centerIDs = (long*)malloc((size_t)centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc((size_t)chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) points.p[i].coord = &block[i * dim];

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc((size_t)centersize * sizeof(Point));
  centers.num = 0;
  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %lu points\n", numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) points.p[i].weight = 1.0;

    switch_membership = (char*)malloc((size_t)points.num * sizeof(char));
    is_center = (bool*)calloc((size_t)points.num, sizeof(bool));
    center_table = (int*)malloc((size_t)points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) break;
  }

  switch_membership = (char*)malloc((size_t)centers.num * sizeof(char));
  is_center = (bool*)calloc((size_t)centers.num, sizeof(bool));
  center_table = (int*)malloc((size_t)centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(centerIDs);
  free(centerBlock);
  free(points.p);
  free(centers.p);
  free(block);
}

